const P=6;let cP=1;let cC=null;let fP=[...blogPosts];const FINAL_PAGE_LINK="#";function generateBlogSchema(){function tA(p){return p.startsWith('http://')||p.startsWith('https://')?p:window.location.origin+(p.startsWith('/')?p:'/'+p);}const bP=blogPosts.map(p=>({"@type":"BlogPosting","headline":p.title,"description":p.text.substring(0,200)+(p.text.length>200?"...":""),"url":tA(p.link),"datePublished":p.date,"dateModified":p.date,"image":tA(p.image),"author":{"@type":"Person","name":p.authorName||"ابوالفضل شهاب"}}));const s={"@context":"https://schema.org","@type":"Blog","name":"وبلاگ IVAN OMGRU | مقالات آموزشی","url":"https://ivan-omgru.ir/Mypageruir/blog.html","description":"آخرین مطالب و مقالات آموزشی در حوزه زبان روسی، مهاجرت، برنامه‌نویسی و طراحی وب","inLanguage":"fa-IR","author":{"@type":"Person","name":"ابوالفضل شهاب"},"publisher":{"@type":"Organization","name":"IVAN OMGRU"},"blogPost":bP};const id='blog-schema-script';let script=document.getElementById(id);if(script){script.textContent=JSON.stringify(s,null,2);}else{script=document.createElement('script');script.id=id;script.type='application/ld+json';script.textContent=JSON.stringify(s,null,2);document.head.appendChild(script);}}function updateFilteredPosts(){let f=[...blogPosts];if(cC&&cC!==0){f=f.filter(p=>p.catId===cC);}const s=document.getElementById("blog-sort")?.value||"newest";if(s==="newest"){f=f.reverse();}else{f=[...f];}fP=f;}function createBlogPostCard(p){const h=p.image&&p.image.trim()!=="";const ih=h?'<img src="'+p.image+'" loading="lazy" alt="'+p.title+'">':'<div class="glass-placeholder"></div>';const nc=h?"":"no-image";return '<div class="col-xl-4 col-lg-4 col-md-6 wow fadeInUp" data-wow-delay="100ms"><div class="blog-two__single '+nc+'"><div class="blog-two__img">'+ih+'<div class="blog-two__date"><span class="icon-calendar"></span><p>'+p.date+'</p></div></div><div class="blog-two__content"><div class="blog-two__meta-box"><ul class="blog-two__meta list-unstyled"><li><a href="'+p.link+'"><span class="icon-tags"></span>'+p.category+'</a></li><li><a href="'+p.link+'"><span class="icon-clock"></span>'+p.readingTime+'</a></li></ul></div><h3 class="blog-two__title"><a href="'+p.link+'">'+p.title+'</a></h3><p class="blog-two__text">'+p.text+'</p></div><div class="courses-two__content"><div class="courses-two__btn-and-client-box"><div class="courses-two__btn-box"><a href="'+p.link+'" class="thm-btn-two"><span>مشاهده بیشتر</span><i class="far fa-angle-double-left"></i></a></div><div class="courses-two__client-box"><div class="courses-two__client-img"><img src="'+p.authorImage+'" loading="lazy" alt="'+p.authorName+'"></div><div class="courses-two__client-content"><h4>'+p.authorName+'</h4><p><span class="odometer" data-count="'+p.authorFollowers+'">0</span><i>+</i> دنبال کننده</p></div></div></div></div></div>';}function updateBlogStats(){const t=fP.length;const s=Math.min(P*cP,t);const e=document.getElementById("blog-stats");if(e){e.innerText='نمایش '+s+' مقاله از '+t+' مقاله';}}function toggleBlogLoadMore(){const t=fP.length;const tp=Math.ceil(t/P);const b=document.getElementById('blog-load-more-btn');if(!b)return;if(cP===tp&&tp>0){b.innerHTML='<a href="'+FINAL_PAGE_LINK+'" class="thm-btn-two"><span>مشاهده بیشتر مقالات</span><i class="far fa-angle-double-left"></i></a>';b.style.display='inline-flex';b.removeEventListener('click',blogLoadMoreHandler);return;}if(cP<tp){b.innerHTML='<span>بیشتر</span><i class="far fa-angle-double-left"></i>';b.style.display='inline-flex';b.removeEventListener('click',blogLoadMoreHandler);b.addEventListener('click',blogLoadMoreHandler);}else{b.style.display='none';}}function blogLoadMoreHandler(){cP++;renderBlogPosts(cP,true);}function renderBlogPagination(){const tp=Math.ceil(fP.length/P);const ul=document.getElementById("blog-pagination");if(!ul||tp<=1){if(ul)ul.innerHTML="";return;}let h="";h+='<li class="prev"><a href="#" data-page="'+(cP-1)+'" '+(cP===1?'style="pointer-events:none;opacity:0.5;"':'')+'><i class="fas fa-arrow-right"></i></a></li>';for(let i=1;i<=tp;i++){const ps=i<10?"0"+i:i;h+='<li class="count '+(i===cP?"active":"")+'"><a href="#" data-page="'+i+'">'+ps+'</a></li>';}h+='<li class="next"><a href="#" data-page="'+(cP+1)+'" '+(cP===tp?'style="pointer-events:none;opacity:0.5;"':'')+'><i class="fas fa-arrow-left"></i></a></li>';ul.innerHTML=h;}function renderBlogPosts(page=cP,append=false){const c=document.getElementById("blog-posts-container");if(!c)return;if(fP.length===0){if(!document.getElementById('loading-dots-style')){const s=document.createElement('style');s.id='loading-dots-style';s.textContent='.loading-dots span{animation:dotBlink 1.4s infinite both;font-size:2.0rem;font-weight:bold;color:#ff9437;display:inline-block;margin:0 2px;}.loading-dots span:nth-child(2){animation-delay:0.2s;}.loading-dots span:nth-child(3){animation-delay:0.4s;}@keyframes dotBlink{0%{opacity:0.2;transform:translateY(0);}50%{opacity:1;transform:translateY(-5px);}100%{opacity:0.2;transform:translateY(0);}}';document.head.appendChild(s);}c.innerHTML='<div class="col-12 text-center py-5"><div class="alert alert-info" style="background: #f8f9faa0; border-right: 5px solid #1976D2;"><h4 style="color: #ff6a00;">⚠️ مقاله‌ای یافت نشد</h4><p style="font-size: 1.2rem;">پستی فعلاً توسط <strong>IVAN OMGRU</strong> مدیر وب‌سایت بارگذاری نشده است.</p><p>به زودی مقالات جدیدی در این دسته منتشر خواهد شد.</p><div class="loading-dots" style="margin-top: 15px;"><span>.</span><span>.</span><span>.</span></div></div></div>';const e=document.getElementById("blog-stats");if(e)e.innerText='نمایش ۰ مقاله از ۰ مقاله';const b=document.getElementById("blog-load-more-btn");if(b)b.style.display="none";const u=document.getElementById("blog-pagination");if(u)u.innerHTML="";return;}const s=P*(page-1);const e=s+P;const pt=fP.slice(s,e);if(!append){c.innerHTML="";}pt.forEach(p=>{c.insertAdjacentHTML("beforeend",createBlogPostCard(p));});updateBlogStats();toggleBlogLoadMore();renderBlogPagination();if(typeof WOW!=="undefined"&&!append){new WOW().init();}if(typeof Odometer!=="undefined"){document.querySelectorAll(".odometer").forEach(el=>{const cnt=el.getAttribute("data-count");if(cnt){el.innerText=cnt;}});}}function updateCategoryUI(){document.querySelectorAll('.main-menu__category-sub-menu li').forEach(li=>{const c=parseInt(li.getAttribute('data-category'));if(c===0&&cC===null){li.classList.add('active');}else if(c===cC){li.classList.add('active');}else{li.classList.remove('active');}});document.querySelectorAll('.gallery-filter button').forEach(btn=>{const f=parseInt(btn.getAttribute('data-filter'));if(f===0&&cC===null){btn.classList.add('active');}else if(f===cC){btn.classList.add('active');}else{btn.classList.remove('active');}});}function refreshBlog(){updateFilteredPosts();cP=1;renderBlogPosts(1,false);updateCategoryUI();}document.addEventListener("DOMContentLoaded",function(){generateBlogSchema();const categoryItems=document.querySelectorAll('.main-menu__category-sub-menu li');function setActiveCategory(selectedLi){categoryItems.forEach(li=>li.classList.remove('active'));if(selectedLi)selectedLi.classList.add('active');}categoryItems.forEach(item=>{item.addEventListener('click',function(e){e.preventDefault();const catId=parseInt(this.getAttribute('data-category'));if(catId===0){cC=null;setActiveCategory(this);}else{if(cC===catId){cC=null;setActiveCategory(null);}else{cC=catId;setActiveCategory(this);}}refreshBlog();});});document.querySelectorAll('.gallery-filter button').forEach(btn=>{btn.addEventListener('click',function(e){e.preventDefault();const catId=parseInt(this.getAttribute('data-filter'));cC=(catId===0)?null:catId;refreshBlog();});});const blogSortSelect=document.getElementById("blog-sort");if(blogSortSelect){let lastSortValue=blogSortSelect.value;blogSortSelect.addEventListener("change",function(){if(lastSortValue!==this.value){lastSortValue=this.value;refreshBlog();}});setInterval(function(){if(blogSortSelect.value!==lastSortValue){lastSortValue=blogSortSelect.value;refreshBlog();}},300);}const blogLoadMore=document.getElementById("blog-load-more-btn");if(blogLoadMore){blogLoadMore.addEventListener("click",blogLoadMoreHandler);}const blogPagination=document.getElementById("blog-pagination");if(blogPagination){blogPagination.addEventListener("click",function(e){const link=e.target.closest("a[data-page]");if(!link)return;e.preventDefault();const page=parseInt(link.getAttribute("data-page"));const totalPages=Math.ceil(fP.length/P);if(!isNaN(page)&&page>=1&&page<=totalPages){cP=page;renderBlogPosts(cP,false);updateCategoryUI();}});}refreshBlog();});
